sources.styles\\blocks\\page.scss:
.page {
  font-family: "Inter", sans-serif;
  scroll-behavior: smooth;

  &__body {
    margin: 0;

    &--with-menu {
      overflow: hidden;
    }
  }

  &__menu {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;

    transform: translateX(-100%);
    transition: $transion;

    &:target {
      transform: translateX(0);
    }
  }

  &__section {
    margin-bottom: 120px;
  }

  &__section-title {
    margin: 0 0 48px;
    font-weight: 700;
    font-size: 32px;
    line-height: 32px;
    text-align: center;
    letter-spacing: -1.5px;
    padding: 0;

    color: $colorBlack;

    @include onTablet {
      font-size: 40px;
      line-height: 40px;
      margin: 0 0 64px;
    }
    @include onDesktop {
      font-size: 48px;
      line-height: 48px;
    }
  }

}

sources.styles\\utils\\_mixins.scss:
@mixin onDesktop {
  @media(min-width: 1020px) {
    @content;
  }
}

@mixin onTablet {
  @media(min-width: 744px) {
    @content;
  }
}

@mixin top-action {
  --icon-width: 18px;

  display: grid;
  grid-template-columns: 1fr var(--icon-width) var(--icon-width);
  align-items: center;
  gap: 30px;

  @include onTablet {
    --icon-width: 24px;
    gap: 40px;
  }
}

