sources.styles\\blocks\\header.scss:
.header {
  background-size: cover;
  background-position: center;
  background-image: url(../images/BOSE/header-322.png);

  @include onTablet {
    background-image: url(../images/header744.png);
  }

  @include onDesktop {
    background-image: url(../images/header-desktop.png);
  }

  &__content {
    display: flex;

    flex-direction: column;
    justify-content: space-between;

    box-sizing: border-box;
    height: 100vh;
    padding: $headerTopPadding 0 94px;

    @include onTablet {
      padding: 52px 0 64px;
    }

  }

  &__top {
    @include top-action;
  }

  &__title {
    font-family: inherit;
    font-weight: 800;
    font-style: italic;
    font-size: 32px;
    line-height: 100%;
    letter-spacing: -1.5px;
    color: $colorBlack;
    margin: 0;
    padding: 0;

    &::before {
      content: "";
      background-image: url(../images/favicon.svg);
      display: block;
      margin-bottom: 16px;
      width: 32px;
      height: 27px;

      background-position: center;
      background-repeat: no-repeat;
      background-size: cover;
    }

    @include onTablet() {
      font-size: 40px;
      line-height: 100%;

      &::before {
        content: "";
        background-image: url(../images/SoundWaves.svg);
        display: block;
        width: 63px;
        height: 76px;
      }
    }

    @include onDesktop {
      font-size: 48px;
      line-height: 100%;
    }
  }
}

sources.styles\\blocks\\menu.scss:
.menu {
  box-sizing: border-box;
  height: 100vh;
  padding: $headerTopPadding 0;

  background-color: #e8eff9;
  overflow-y: auto;

  &__content {
    @include onTablet {
      padding: 52px 0 64px;
    }
  }

  &__top {
    @include top-action;
    padding-bottom: 54px;
  }

  &__list {
    margin: 0 0 40px;
    padding: 0;
    list-style: none;
  }

  &__item {
    margin-bottom: 24px;

    &:last-child {
      margin-bottom: 0;
    }
  }

  &__link {
    display: block;
    width: max-content;
    padding-bottom: 8px;
    border-bottom: 1px solid transparent;
    font-weight: 700;
    font-size: 22px;
    line-height: 22px;
    font-style: normal;
    letter-spacing: 2px;
    text-transform: uppercase;
    text-decoration: none;
    color: $colorBlack;
    transition: border-color $transion;


    &:hover {
      border-color: $colorBlack;
    }
  }

  &__call {
    display: block;
    width: max-content;

    font-weight: 700;
    color: $colorBlack;
    text-transform: uppercase;
    text-decoration: none;
    transition: $transion;

    &:hover {
      color: $colorSecond;
    }

    &--phone {
      margin-bottom: 16px;
      font-size: 16px;
      line-height: 27px;
    }

    &--action {
      font-size: 12px;
      line-height: 16px;
      text-transform: uppercase;

      padding-bottom: 8px;
      border-bottom: 1px solid;
      letter-spacing: 2px;
    }
  }

  &__icon {
    visibility: hidden;
  }

}

sources.styles\\blocks\\recommended.scss:
.recommended {
  display: flex;
  place-content: center;

  &__title {
    font-weight: 700;
    font-size: 16px;
    line-height: 22px;
    color: $colorBlack;
    margin: 0 0 8px;
    font-family: inherit;
    font-style: normal;
  }

  &__photo {
    display: block;
    width: 280px;
    height: 277px;
    margin: 0 0 32px;
    transition: $transion;

    &:hover {
      transform: scale(1.1);
      box-shadow: $box-shadow;
    }

    @include onTablet {
      width: 392px;
      height: 387px;
    }

    @include onDesktop {
      width: 324px;
      height: 320px;
    }
  }

  &__discribtion {
    margin: 0 0 12px;
  }

  &__price {
    margin: 0 0 48px;
    font-weight: 700;
    font-size: 16px;
    line-height: 140%;
    color: $colorBlack;

    &--last-child {
      margin-bottom: 0;
    }

    @include onTablet {
      margin-bottom: 0;
    }
  }

}

sources.styles\\blocks\\category-prod.scss:
.category-prod {
  &__photos-container {
    position: relative;

    box-sizing: border-box;
    width: 100%;
    max-height: 320px;
    margin-bottom: 16px;
    overflow: hidden;
    transition: $transion;

    &:hover {
      transform: scale(1.06);
      box-shadow: $box-shadow;
    }

    &::after {
      content: "";
      display: block;
      padding-bottom: 100%;
    }

    @include onTablet {
      height: 187px;
      padding-bottom: 0;
    }

    @include onDesktop {
      height: 320px;
      padding-bottom: 0;
    }

  }

  &__photo {
    position: absolute;
    width: 100%;
    height: 100%;

    object-fit: cover;
    object-position: center;
  }

  &__description {
    font-family: inherit;
    font-style: normal;
    font-weight: 900;
    font-size: 16px;
    line-height: 140%;
    color: $colorBlack;

    @include onTablet {
      font-size: 24px;
    }
  }
}

sources.styles\\blocks\\button.scss:
.button {
  display: flex;
  justify-content: center;
  align-items: center;

  box-sizing: border-box;
  width: 100%;
  height: 56px;
  background-color: $colorBlack;
  border-radius: 40px;
  color: #fff;
  border: 3px solid $colorBlack;

  text-decoration: none;
  font-weight: 700;
  font-size: 16px;
  line-height: 27px;

  cursor: pointer;
  transition: all $transion;

  &:hover {
    background-color: #fff;
    color: $colorBlack;
  }

  &:active {
    background-color: #111;
    color: #fff;
  }
}

