sources.styles\\blocks\\form-field.scss:
.form-field {
  box-sizing: border-box;
  display: block;
  height: 48px;
  width: 100%;
  border: 1px solid transparent;
  background-color: #f8f8fa;
  font-family: inherit;
  color: $colorBlack;
  border-radius: 40px;
  padding: 14px 16px;

  &::placeholder {
    font-size: 14px;
    line-height: 20px;
    color: #7e7e83;

  }

  &:hover {
    border-color: #d5d7de;
  }

  &:focus {
    border-color: $colorBlack;
    outline: none;
  }

  &--textarea {
    height: 148px;
    font-family: inherit;
    resize: none;

  }

}

